-- Luke Chapter 16
-- Theme: Faithful Stewardship and the Eternal Stakes of Earthly Choices
-- 31 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 16,
  'Luke 16 contains two of the most difficult and most discussed parables in the Gospels: the unjust steward (vv.1-13) and the rich man and Lazarus (vv.19-31), with a section of standalone sayings about money, law, and divorce in between (vv.14-18). The chapter is unified by its persistent concern with the relationship between wealth and eternity. The Pharisees, who "were covetous" (v.14), serve as the audience for both major units, and their sneering response to Jesus''s teaching on money becomes the occasion for some of the most penetrating moral and eschatological instruction in the Gospel.',
  'The parable of the unjust steward (vv.1-9) is widely acknowledged as the most difficult parable in Luke. A dishonest manager, about to be dismissed, reduces his master''s debtors'' bills to secure future goodwill. Remarkably, his master commends him — not for the dishonesty but for the shrewdness. Jesus draws the lesson: the "children of this world" are more shrewd in worldly matters than the "children of light" are in using wealth for kingdom purposes. The point is not to imitate the steward''s dishonesty but his urgency and shrewdness in using present resources to secure a future.',
  'The four standalone sayings (vv.10-13) apply the parable''s lesson: faithfulness in small things predicts faithfulness in large; one cannot serve both God and mammon. These sayings are interrupted by the Pharisees'' derision (v.14), which provokes Jesus''s address about the law and the kingdom (vv.15-18): God knows the heart (v.15); the law and prophets were until John — now the kingdom is preached (v.16); the law is easier to abandon than heaven and earth (v.17); divorce is a matter of the law''s integrity (v.18). These verses are contextual bridges, not isolated fragments.',
  'The parable of the rich man and Lazarus (vv.19-31) is Luke''s most extended narrative about the afterlife. A nameless rich man feasts lavishly while Lazarus — the only named character in any of Jesus''s parables — begs at his gate. Both die; their positions are reversed. Lazarus rests in Abraham''s bosom; the rich man is tormented in Hades. A fixed gulf prevents movement between the realms. The rich man''s requests (water, then a resurrection mission to warn his brothers) are both denied. The final word is devastating: "If they hear not Moses and the prophets, neither will they be persuaded, though one rose from the dead" — pointing both to Israel''s coming rejection of the risen Jesus and to the sufficiency of Scripture.',
  'οἰκονόμος (oikonomos)',
  'oikonomos means a steward, an estate manager, a household administrator. Derived from oikos (house) + nemō (to manage, distribute), it refers to a trusted agent who manages another person''s property and resources. In Luke 16, the word drives the chapter: the unjust steward (oikonomos) is the parable''s protagonist (vv.1,2,3,4,8), and the lesson about faithful stewardship (v.10-12) flows from his example. The chapter''s theology of wealth rests on this concept: all earthly resources belong to another (God); believers are stewards, not owners, and will give account of how they used what was entrusted to them.',
  '["The Parable of the Unjust Steward: Shrewd Use of Wealth (vv.1-9)","Faithful Stewardship: God and Mammon Cannot Both Be Served (vv.10-13)","The Pharisees'' Covetousness and the Law''s Permanence (vv.14-18)","The Rich Man and Lazarus: Wealth, Poverty, and Eternal Reversal (vv.19-31)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And he said also unto his disciples, There was a certain rich man, which had a steward; and the same was accused unto him that he had wasted his goods.', 'Ἔλεγεν δὲ καὶ πρὸς τοὺς μαθητάς, Ἄνθρωπός τις ἦν πλούσιος ὃς εἶχεν οἰκονόμον, καὶ οὗτος διεβλήθη αὐτῷ ὡς διασκορπίζων τὰ ὑπάρχοντα αὐτοῦ.', 'Elegen de kai pros tous mathētas, Anthrōpos tis ēn plousios hos eichen oikonomōn, kai houtos diEblēthē autō hōs diaskorpizōn ta huparchonta autou.', '"Also unto his disciples" — the audience shifts from the Pharisees (chapter 15) to the disciples, though the Pharisees are still present (v.14). "A steward" (oikonomōn — estate manager, the one who manages the master''s household). "Was accused" (diEblēthē — was brought as an accusation against, slandered; from diaballō, to throw across, slander) — the source of the report is unclear; the accusation may be malicious or accurate. "Wasted his goods" (diaskorpizōn — scattering, squandering; the same word used of the prodigal in 15:13) — connecting the two chapters.', NULL),
  (2, 'And he called him, and said unto him, How is it that I hear this of thee? give an account of thy stewardship; for thou mayest be no longer steward.', 'καὶ φωνήσας αὐτὸν εἶπεν αὐτῷ, Τί τοῦτο ἀκούω περὶ σοῦ; ἀπόδος τὸν λόγον τῆς οἰκονομίας σου· οὐ γὰρ δύνῃ ἔτι οἰκονομεῖν.', 'kai phōnēsas auton eipen autō, Ti touto akouō peri sou; apodos ton logon tēs oikonomias sou; ou gar dunē eti oikonomEin.', '"Give an account" (apodos ton logon tēs oikonomias — render the reckoning of your stewardship) — a formal audit is demanded. "For thou mayest be no longer steward" (ou gar dunē eti oikonomEin — you can no longer manage the estate) — the dismissal is imminent but not yet final. A window of time exists, and the steward will use it with remarkable shrewdness. The parable depicts the crisis of accountability — a moment every human being will ultimately face before God.', NULL),
  (3, 'Then the steward said within himself, What shall I do? for my lord taketh away from me the stewardship: I cannot dig; to beg I am ashamed.', 'εἶπεν δὲ ἐν ἑαυτῷ ὁ οἰκονόμος, Τί ποιήσω, ὅτι ὁ κύριός μου ἀφαιρεῖται τὴν οἰκονομίαν ἀπ'' ἐμοῦ; σκάπτειν οὐκ ἰσχύω, ἐπαιτεῖν αἰσχύνομαι.', 'eipen de en heautō ho oikonomos, Ti poiēsō, hoti ho kurios mou aphaireitai tēn oikonomian ap'' emou; skaptein ouk ischuō, epaitein aischUnomai.', '"Said within himself" (en heautō — thinking within, the internal monologue cf. the prodigal in 15:17) — a moment of crisis calculation. "I cannot dig" (skaptein ouk ischuō — I lack the strength for manual labor) and "to beg I am ashamed" (epaitein aischunomai — begging would humiliate me) — two options excluded. The steward is neither physically able to labor nor willing to beg. He must find a third way. His analysis is clear-eyed and his solution will be bold.', NULL),
  (4, 'I am resolved what to do, that, when I am put out of the stewardship, they may receive me into their houses.', 'ἔγνων τί ποιήσω, ἵνα, ὅταν μετασταθῶ τῆς οἰκονομίας, δέξωνταί με εἰς τοὺς οἴκους αὐτῶν.', 'egnōn ti poiēsō, hina, hotan metastathō tēs oikonomias, dexōntai me eis tous oikous autōn.', '"I am resolved" (egnōn — I know, I have decided, aorist of decisive knowledge) — the solution crystallizes in a moment. "When I am put out" (metastathō — when I am transferred, removed, dismissed) — his dismissal is certain; the question is what happens after. "They may receive me into their houses" (dexōntai me — they will welcome me) — securing a social network before the axe falls. The shrewdness is in creating future obligations from present authority before that authority expires.', NULL),
  (5, 'So he called every one of his lord''s debtors unto him, and said unto the first, How much owest thou unto my lord?', 'καὶ προσκαλεσάμενος ἕνα ἕκαστον τῶν χρεοφειλετῶν τοῦ κυρίου ἑαυτοῦ ἔλεγεν τῷ πρώτῳ, Πόσον ὀφείλεις τῷ κυρίῳ μου;', 'kai proskalesamenos hena hekaston tōn chreOpheiletōn tou kuriou heautou elegen tō prōtō, Poson opheileis tō kuriō mou?', '"Every one of his lord''s debtors" (hena hekaston tōn chreophEiletōn — each one of the debt-holders) — a systematic operation, not a random act. These were likely tenant farmers or merchants who owed rent or lease payments to the master, perhaps denominated in produce rather than money. The steward still has authority over the estate''s business records; he acts within his (expiring) legal authority to restructure debts — possibly reducing the portion that represented his own commission.', NULL),
  (6, 'And he said, An hundred measures of oil. And he said unto him, Take thy bill, and sit down quickly, and write fifty.', 'ὁ δὲ εἶπεν, Ἑκατὸν βάτους ἐλαίου. ὁ δὲ εἶπεν αὐτῷ, Δέξαι σου τὸ γράμμα καὶ καθίσας ταχέως γράψον πεντήκοντα.', 'ho de eipen, Hekaton batous elaiou. ho de eipen autō, Dexai sou to gramma kai kathisas tacheōs grapsOn pentēkonta.', 'A hundred baths (batous) of oil equaled about 875 gallons — a large quantity representing perhaps a year''s production from a significant olive grove. Reducing it to fifty was a 50% reduction, worth about 500 denarii (18 months'' wages). "Quickly" (tacheōs — at once, without hesitation) — the steward is acting under time pressure before his dismissal is formalized. The debtors'' enthusiasm to rewrite the bills (they received a windfall) secures their future goodwill toward him.', NULL),
  (7, 'Then said he to another, And how much owest thou? And he said, An hundred measures of wheat. And he said unto him, Take thy bill, and write fourscore.', 'ἔπειτα ἑτέρῳ εἶπεν, Σὺ δὲ πόσον ὀφείλεις; ὁ δὲ εἶπεν, Ἑκατὸν κόρους σίτου. λέγει αὐτῷ, Δέξαι σου τὸ γράμμα καὶ γράψον ὀγδοήκοντα.', 'epeita heterō eipen, Su de poson opheileis; ho de eipen, Hekaton korous sitou. legei autō, Dexai sou to gramma kai grapsOn ogdoēkonta.', 'A hundred cors (korous) of wheat equaled about 1,100 bushels — a large harvest debt. Reducing it to eighty (a 20% reduction) was still significant. The different percentage reductions (50% oil, 20% wheat) may reflect different interest rates or simply the steward''s calculation of what was needed to secure each debtor''s friendship. The systematic reduction of debts creates an entire social network of people indebted to the steward''s generosity before his dismissal takes effect.', NULL),
  (8, 'And the lord commended the unjust steward, because he had done wisely: for the children of this world are in their generation wiser than the children of light.', 'καὶ ἐπῄνεσεν ὁ κύριος τὸν οἰκονόμον τῆς ἀδικίας ὅτι φρονίμως ἐποίησεν· ὅτι οἱ υἱοὶ τοῦ αἰῶνος τούτου φρονιμώτεροι ὑπὲρ τοὺς υἱοὺς τοῦ φωτὸς εἰς τὴν γενεὰν τὴν ἑαυτῶν εἰσιν.', 'kai epēnesen ho kurios ton oikonomOn tēs adikias hoti phronimōs epoiēsen; hoti hoi huioi tou aiōnos toutou phronimōteroi huper tous huious tou phōtos eis tēn genean tēn heautōn eisin.', '"Commended" (epēnesen — praised, commended the wisdom, not the dishonesty) "the unjust steward" (ton oikonomon tēs adikias — the steward of unrighteousness) — Luke clarifies the steward''s moral character while reporting the master''s specific admiration for his shrewdness (phronimōs — prudently, wisely). "Children of this world" (huioi tou aiōnos toutou) versus "children of light" (huious tou phōtos) — the children of this age apply more practical wisdom to their earthly concerns than believers apply to kingdom concerns.', NULL),
  (9, 'And I say unto you, Make to yourselves friends of the mammon of unrighteousness; that, when ye fail, they may receive you into everlasting habitations.', 'καὶ ἐγὼ ὑμῖν λέγω, ποιήσατε ἑαυτοῖς φίλους ἐκ τοῦ μαμωνᾶ τῆς ἀδικίας, ἵνα ὅταν ἐκλίπῃ δέξωνται ὑμᾶς εἰς τὰς αἰωνίους σκηνάς.', 'kai egō humin legō, poiēsate heautois philous ek tou mamōna tēs adikias, hina hotan eklipē dexōntai humas eis tas aiōnious skēnas.', '"Mammon of unrighteousness" (mamōna tēs adikias — wealth of this age, tainted worldly money; Aramaic māmōnāʾ) — not money per se but the money of this fallen world system. "Make friends" — use wealth generously so that when it fails (eklipē — runs out, gives out) those you helped "may receive you into everlasting habitations" (tas aiōnious skēnas — the eternal dwellings, the tents/tabernacles of the kingdom). The point: use transient earthly wealth to invest in eternal relationships and kingdom causes.', NULL),
  (10, 'He that is faithful in that which is least is faithful also in much: and he that is unjust in the least is unjust also in much.', 'ὁ πιστὸς ἐν ἐλαχίστῳ καὶ ἐν πολλῷ πιστός ἐστιν, καὶ ὁ ἐν ἐλαχίστῳ ἄδικος καὶ ἐν πολλῷ ἄδικός ἐστιν.', 'ho pistos en elachistō kai en pollō pistos estin, kai ho en elachistō adikos kai en pollō adikos estin.', 'A standalone proverb that draws the lesson from the parable. "Faithful in that which is least" (pistos en elachistō — trustworthy in the smallest thing) — character is consistent: the person who is faithful with small matters will be faithful with large ones; the person who cheats in small things will cheat in large ones. Money is one of the smallest tests of character (v.11: "unrighteous mammon"); how you handle it reveals what you would do with true, eternal riches.', NULL),
  (11, 'If therefore ye have not been faithful in the unrighteous mammon, who will commit to your trust the true riches?', 'εἰ οὖν ἐν τῷ ἀδίκῳ μαμωνᾷ πιστοὶ οὐκ ἐγένεσθε, τὸ ἀληθινὸν τίς ὑμῖν πιστεύσει;', 'ei oun en tō adikō mamōna pistoi ouk egenesthe, to alēthinon tis humin pisteusei?', '"Unrighteous mammon" (tō adikō mamōna — the dishonest wealth, worldly money) as a test of "true riches" (to alēthinon — the genuine, real thing, a Johannine word here in Luke). If the test of earthly money is failed — through greed, hoarding, or misuse — who will entrust to that person the real, eternal resources of the kingdom? Material wealth is the proving ground for spiritual faithfulness. Generosity with money demonstrates readiness for kingdom responsibility.', NULL),
  (12, 'And if ye have not been faithful in that which is another man''s, who shall give you that which is your own?', 'καὶ εἰ ἐν τῷ ἀλλοτρίῳ πιστοὶ οὐκ ἐγένεσθε, τὸ ὑμέτερον τίς δώσει ὑμῖν;', 'kai ei en tō allotriō pistoi ouk egenesthe, to humeteron tis dōsei humin?', '"Another man''s" (tō allotriō — belonging to another, foreign to oneself) — all earthly wealth belongs to God; we are stewards, not owners. "That which is your own" (to humeteron — what is genuinely yours) — the kingdom inheritance that believers will receive as their own (Eph 1:14; Rom 8:17). The contrast is striking: present wealth is borrowed; eternal inheritance is truly personal. Faithfulness with borrowed earthly goods qualifies the steward for ownership of eternal ones.', NULL),
  (13, 'No servant can serve two masters: for either he will hate the one, and love the other; or else he will hold to the one, and despise the other. Ye cannot serve God and mammon.', 'Οὐδεὶς οἰκέτης δύναται δυσὶ κυρίοις δουλεύειν· ἢ γὰρ τὸν ἕνα μισήσει καὶ τὸν ἕτερον ἀγαπήσει, ἢ ἑνὸς ἀνθέξεται καὶ τοῦ ἑτέρου καταφρονήσει. οὐ δύνασθε Θεῷ δουλεύειν καὶ μαμωνᾷ.', 'Oudeis oiketēs dunatai dusin kuriois douleuein; ē gar ton hena misēsei kai ton heteron agapēsei, ē henos anthexetai kai tou heterou kataphronēsei. ou dunasthe Theō douleuein kai mamōna.', '"No servant" (Oudeis oiketēs — not one household slave) can serve two masters who have competing demands. The verb "serve" (douleuein — slave-service, total loyalty) requires undivided allegiance. The two possible responses — love/hate, hold to/despise — describe not occasional preference but fundamental orientation of the will. "Ye cannot" (ou dunasthe — you are not able, it is an impossibility) to give ultimate loyalty to both God and money. This is the chapter''s theological center and the definition of the Pharisees'' failure (v.14).', NULL),
  (14, 'And the Pharisees also, who were covetous, heard all these things: and they derided him.', 'Ἤκουον δὲ ταῦτα πάντα καὶ οἱ Φαρισαῖοι φιλάργυροι ὑπάρχοντες, καὶ ἐξεμυκτήριζον αὐτόν.', 'Ēkouon de tauta panta kai hoi Pharisaioi philarguroi huparchontes, kai exemuktērizon auton.', '"Covetous" (philarguroi — money-lovers, literally: loving silver; philos + arguros) — Luke identifies the Pharisees'' characteristic sin in relation to this discourse. They "heard all these things" but their response was derision, not conviction. "Derided him" (exemuktērizon — were sneering at him, literally: turning up the nose at, contemptuous mockery) — the imperfect suggests continuous, repeated sneering. Their response to teaching about money reveals their enslavement to it; the mockery is the proof of the indictment.', NULL),
  (15, 'And he said unto them, Ye are they which justify yourselves before men; but God knoweth your hearts: for that which is highly esteemed among men is abomination in the sight of God.', 'καὶ εἶπεν αὐτοῖς, Ὑμεῖς ἐστε οἱ δικαιοῦντες ἑαυτοὺς ἐνώπιον τῶν ἀνθρώπων, ὁ δὲ Θεὸς γινώσκει τὰς καρδίας ὑμῶν· ὅτι τὸ ἐν ἀνθρώποις ὑψηλὸν βδέλυγμα ἐνώπιον τοῦ Θεοῦ ἐστιν.', 'kai eipen autois, Humeis este hoi dikaioUntes heautous enōpion tōn anthrōpōn, ho de Theos ginōskei tas kardias humōn; hoti to en anthrōpois hupsēlon bdelugma enōpion tou Theou estin.', '"Justify yourselves before men" (dikaioUntes heautous enōpion tōn anthrōpōn — declaring yourselves righteous in men''s eyes, performing righteousness for human approval) — the Pharisaic system of public reputation management. "God knoweth your hearts" (Theos ginōskei tas kardias — God knows, with complete present knowledge, the hearts) — the divine counter-evaluation. "That which is highly esteemed among men is abomination" (bdelugma — an abomination, the strongest OT term for ritual defilement) — what receives the highest human honor may be the most repugnant to God. Their money and reputation are their idols.', NULL),
  (16, 'The law and the prophets were until John: since that time the kingdom of God is preached, and every man presseth into it.', 'Ὁ νόμος καὶ οἱ προφῆται μέχρι Ἰωάννου· ἀπὸ τότε ἡ βασιλεία τοῦ Θεοῦ εὐαγγελίζεται καὶ πᾶς εἰς αὐτὴν βιάζεται.', 'Ho nomos kai hoi prophētai mechri Iōannou; apo tote hē basileia tou Theou euangelizEtai kai pas eis autēn biAzetai.', '"Until John" (mechri Iōannou — up to John, as far as John) — John is the hinge between the age of the Law and Prophets and the age of the kingdom''s proclamation. "Is preached" (euangelizEtai — is being gospelized, proclaimed as good news; the present tense indicates ongoing proclamation). "Every man presseth into it" (pas eis autēn biAzetai — everyone forces his way into it; biAzetai from bia, force or violence) — the kingdom''s arrival is creating urgent, even violent pressing from those desperate to enter, while the Pharisees sneer from outside.', NULL),
  (17, 'And it is easier for heaven and earth to pass, than one tittle of the law to fail.', 'εὐκοπώτερον δέ ἐστιν τὸν οὐρανὸν καὶ τὴν γῆν παρελθεῖν ἢ τοῦ νόμου μίαν κεραίαν πεσεῖν.', 'eukopōteron de estin ton ouranon kai tēn gēn parelthein ē tou nomou mian keraian pesein.', '"One tittle" (mian keraian — one keraia, the smallest stroke of a letter, the ornamental serif) — the most minimal, insignificant mark in the written Law. "Heaven and earth to pass" — the dissolution of the cosmos — is described as easier than the failure of a single tittle of the Law. This is a hyperbolic affirmation of the Law''s eternal validity. In context, the Pharisees'' money-love violates the Law they claim to uphold; Jesus is more faithful to the Law''s demands than they are.', NULL),
  (18, 'Whosoever putteth away his wife, and marrieth another, committeth adultery: and whosoever marrieth her that is put away from her husband committeth adultery.', 'Πᾶς ὁ ἀπολύων τὴν γυναῖκα αὐτοῦ καὶ γαμῶν ἑτέραν μοιχεύει, καὶ πᾶς ὁ ἀπολελυμένην ἀπὸ ἀνδρὸς γαμῶν μοιχεύει.', 'Pas ho apoluōn tēn gunaika autou kai gamōn heteran moicheuei, kai pas ho apolelumenēn apo andros gamōn moicheuei.', 'A standalone saying on divorce, contextually linked to the Law''s permanence (v.17). The Pharisees may have used Hillel''s broad interpretation of Deut 24:1 ("any cause") as a loophole — and the Pharisees'' covetousness (v.14) may have included divorcing wives to pursue wealthier matches. Jesus applies the Law''s integrity to marriage: divorce and remarriage constitutes adultery (moicheuei) against the original covenant. The saying defends both the woman''s dignity and the Law''s intention regarding covenant faithfulness.', NULL),
  (19, 'There was a certain rich man, which was clothed in purple and fine linen, and fared sumptuously every day:', 'Ἄνθρωπος δέ τις ἦν πλούσιος, καὶ ἐνεδιδύσκετο πορφύραν καὶ βύσσον εὐφραινόμενος καθ'' ἡμέραν λαμπρῶς.', 'Anthrōpos de tis ēn plousios, kai enedidusketo porphuran kai busson euphraInomenos kath'' hēmeran lamprōs.', '"Purple and fine linen" (porphuran kai busson) — purple (porphura) was the color of royalty, made from Murex shellfish and extraordinarily expensive; fine linen (bussos — byssus, Egyptian linen of the highest quality) was used for royal and priestly garments. He wore these daily (enedidusketo — was continuously dressed in them, imperfect). "Fared sumptuously" (euphrainomenos lamprōs — feasting brilliantly, in splendid celebration) every day — not occasional luxury but sustained, daily extravagance. His wealth is emphasized to sharpen the contrast with Lazarus.', NULL),
  (20, 'And there was a certain beggar named Lazarus, which was laid at his gate, full of sores,', 'πτωχὸς δέ τις ἦν ὀνόματι Λάζαρος, ἐβέβλητο πρὸς τὸν πυλῶνα αὐτοῦ εἱλκωμένος,', 'ptōchos de tis ēn onomati Lazaros, ebeblēto pros ton pulōna autou heilkōmenos,', '"A certain beggar named Lazarus" — the only named character in any of Jesus''s parables. "Lazarus" (Lazaros — a Greek form of the Hebrew Eleazar, meaning "God helps" or "God is my help") — the name is theologically significant; God is the only help for the helpless poor. "Laid" (ebeblēto — had been thrown down, placed, a past completed action; he was deposited there by others) "at his gate" — the threshold between the rich man''s world and the street. "Full of sores" (heilkōmenos — covered with ulcers, festering wounds).', NULL),
  (21, 'And desiring to be fed with the crumbs which fell from the rich man''s table: moreover the dogs came and licked his sores.', 'καὶ ἐπιθυμῶν χορτασθῆναι ἀπὸ τῶν πιπτόντων ἀπὸ τῆς τραπέζης τοῦ πλουσίου· ἀλλὰ καὶ οἱ κύνες ἐρχόμενοι ἀπέλειχον τὰ ἕλκη αὐτοῦ.', 'kai epithumōn chortasthēnai apo tōn piptontōn apo tēs trapezēs tou plousiou; alla kai hoi kunes erchomenoi apeleichon ta helkē autou.', '"Desiring to be fed" (epithumōn chortasthēnai — longing intensely to be satisfied, the same longing-word used of the prodigal for pig food in 15:16) — with the crumbs (piptontōn — falling things, scraps) from the table. "The dogs came and licked his sores" (hoi kunes...apelichon ta helkē autou) — unclean animals (Gentile dogs, free-roaming scavengers) showed more attention to Lazarus than the rich man did. The dogs'' licking may have been painful; there is no comfort for Lazarus in the present age.', NULL),
  (22, 'And it came to pass, that the beggar died, and was carried by the angels into Abraham''s bosom: the rich man also died, and was buried;', 'ἐγένετο δὲ ἀποθανεῖν τὸν πτωχὸν καὶ ἀπενεχθῆναι αὐτὸν ὑπὸ τῶν ἀγγέλων εἰς τὸν κόλπον Ἀβραάμ· ἀπέθανεν δὲ καὶ ὁ πλούσιος καὶ ἐτάφη.', 'egeneto de apothanein ton ptōchon kai apenechthenai auton hypo tōn angelōn eis ton kolpon Abraam; apethanen de kai ho plousios kai etaphē.', 'Both die — death is the great equalizer. But the rich man "was buried" (etaphē) — a noted social honor; Lazarus''s burial, presumably in a pauper''s grave, is not mentioned. Lazarus "was carried by the angels" (apenechthenai hypo tōn angelōn — was carried away by angels) to "Abraham''s bosom" (ton kolpon Abraam — the place of intimate fellowship with the patriarch, the place of honor at the heavenly banquet). The invisible has become visible; the hidden spiritual reality is now narrated openly.', NULL),
  (23, 'And in hell he lift up his eyes, being in torments, and seeth Abraham afar off, and Lazarus in his bosom.', 'καὶ ἐν τῷ ᾅδῃ ἐπάρας τοὺς ὀφθαλμοὺς αὐτοῦ, ὑπάρχων ἐν βασάνοις, ὁρᾷ Ἀβραὰμ ἀπὸ μακρόθεν καὶ Λάζαρον ἐν τοῖς κόλποις αὐτοῦ.', 'kai en tō hadē eparas tous ophthalmous autou, huparchōn en basanois, hora Abraam apo makrothen kai Lazaron en tois kolpois autou.', '"Hades" (hadē — the realm of the dead, the underworld, not specifically eternal punishment but the intermediate state of the unrighteous). "Being in torments" (huparchōn en basanois — in a state of anguish, torment, the word used for testing the genuineness of metals). "Seeth Abraham afar off" (makrothen — at a great distance) — vision is preserved in the intermediate state; he recognizes Abraham and Lazarus. The one who ignored Lazarus at his gate now sees him from an infinite distance in blessing.', NULL),
  (24, 'And he cried and said, Father Abraham, have mercy on me, and send Lazarus, that he may dip the tip of his finger in water, and cool my tongue; for I am tormented in this flame.', 'καὶ αὐτὸς φωνήσας εἶπεν, Πάτερ Ἀβραάμ, ἐλέησόν με καὶ πέμψον Λάζαρον ἵνα βάψῃ τὸ ἄκρον τοῦ δακτύλου αὐτοῦ ὕδατος καὶ καταψύξῃ τὴν γλῶσσάν μου, ὅτι ὀδυνῶμαι ἐν τῇ φλογὶ ταύτῃ.', 'kai autos phōnēsas eipen, Pater Abraam, eleēson me kai pempson Lazaron hina bapsē to akron tou daktulou autou hudatos kai katahupsē tēn glōssan mou, hoti odunōmai en tē phlogI tautē.', '"Father Abraham" — the rich man appeals to ethnic lineage, the last refuge of covenant presumption. "Have mercy" (eleēson — the mercy-cry, the same cry of the blind man in 18:38) — but mercy extended across the fixed gulf is impossible. "The tip of his finger" — not a cup of water but the slightest possible relief. "I am tormented in this flame" (odunōmai en tē phlogI tautē — I am being continuously tortured in this flame) — the request reveals both the reality of conscious suffering and the complete reversal of earthly conditions.', NULL),
  (25, 'But Abraham said, Son, remember that thou in thy lifetime receivedst thy good things, and likewise Lazarus evil things: but now he is comforted, and thou art tormented.', 'εἶπεν δὲ Ἀβραάμ, Τέκνον, μνήσθητι ὅτι ἀπέλαβες τὰ ἀγαθά σου ἐν τῇ ζωῇ σου, καὶ Λάζαρος ὁμοίως τὰ κακά· νῦν δὲ ὧδε παρακαλεῖται, σὺ δὲ ὀδυνᾶσαι.', 'eipen de Abraam, Teknon, mnēsthēti hoti apElabes ta agatha sou en tē zōē sou, kai Lazaros homoiōs ta kaka; nun de hōde parakaleitai, su de odunasai.', '"Son" (Teknon — child, a word of genuine relationship) — Abraham acknowledges the rich man as a descendant. "Remember" (mnēsthēti — an aorist imperative: fix your memory on this). "Thou receivedst thy good things" (apElabes ta agatha sou — you received back your good things, as if claiming a pre-paid account) — in life, he had his comfort; Lazarus had none. "Now" (nun) — the great reversal is in effect. The word parakEitai (is comforted) for Lazarus is the same root as Paraclete, the divine Comforter.', NULL),
  (26, 'And beside all this, between us and you there is a great gulf fixed: so that they which would pass from hence to you cannot; neither can they pass to us, that would come from thence.', 'καὶ ἐπὶ πᾶσι τούτοις μεταξὺ ἡμῶν καὶ ὑμῶν χάσμα μέγα ἐστήρικται, ὅπως οἱ θέλοντες διαβῆναι ἔνθεν πρὸς ὑμᾶς μὴ δύνωνται, μηδὲ οἱ ἐκεῖθεν πρὸς ἡμᾶς διαπερῶσιν.', 'kai epi pasi toutois metaxu hēmōn kai humōn chasma mega estēriktai, hopōs hoi thelontes diabēnai enthen pros humas mē dūnōntai, mēde hoi ekeithen pros hēmas diaperasin.', '"A great gulf fixed" (chasma mega estēRiktai — a vast chasm has been established, set firmly; a perfect passive indicating permanent, settled reality). The gulf prevents movement in both directions: no relief can come from blessing to torment; no saint can descend to comfort the suffering. The irrevocability of post-mortem conditions is the parable''s most sobering feature: every choice made in this life fixes the eternal destination. There is no purgatory, no second chance, no crossing this gulf.', NULL),
  (27, 'Then he said, I pray thee therefore, father, that thou wouldest send him to my father''s house:', 'εἶπεν δέ, Ἐρωτῶ σε οὖν, πάτερ, ἵνα πέμψῃς αὐτὸν εἰς τὸν οἶκον τοῦ πατρός μου,', 'eipen de, Erōtō se oun, pater, hina pEMpsēs auton eis ton oikon tou patros mou,', 'The first request denied, the rich man makes a second: send Lazarus to his family as a missionary to warn them. He has five brothers still living in the same luxury and indifference. The concern for his family reveals that he is not completely hardened — love for his brothers persists. But the request is still framed as using Lazarus for his own purposes (send him — the same language he had used to treat Lazarus as a servant); even in torment, his social condescension persists.', NULL),
  (28, 'For I have five brethren; that he may testify unto them, lest they also come into this place of torment.', 'ἔχω γὰρ πέντε ἀδελφούς, ὅπως διαμαρτύρηται αὐτοῖς, ἵνα μὴ καὶ αὐτοὶ ἔλθωσιν εἰς τὸν τόπον τοῦτον τῆς βασάνου.', 'echō gar pente adelphous, hopōs diamartUrētai autois, hina mē kai autoi elthōsin eis ton topon touton tēs basanou.', '"Testify unto them" (diamartUrētai — to solemnly testify, to warn with authority) — he wants a resurrection appearance as an undeniable evidence. "This place of torment" (ton topon touton tēs basanou) — he is fully aware of the nature of his condition. The request is theologically significant: he implicitly claims that he and his brothers did not have sufficient evidence to believe. Abraham''s response will directly refute this claim — they have Moses and the prophets, and that is sufficient.', NULL),
  (29, 'Abraham saith unto him, They have Moses and the prophets; let them hear them.', 'λέγει δὲ Ἀβραάμ, Ἔχουσι Μωϋσέα καὶ τοὺς προφήτας· ἀκουσάτωσαν αὐτῶν.', 'legei de Abraam, Echousi Mōūsea kai tous prophētas; akousatōsan autōn.', '"Moses and the prophets" (Mōūsea kai tous prophētas) — the entire OT Scripture. "Let them hear them" (akousatōsan autōn — let them listen to, obey, heed them). The Scripture is declared sufficient for the knowledge of God, his moral demands, and the way of repentance. The implication is that the rich man and his brothers had this sufficient revelation and chose to ignore it. A resurrection appearance would not change hearts that have already rejected the Scripture — it would be another miracle to explain away.', NULL),
  (30, 'And he said, Nay, father Abraham: but if one went unto them from the dead, they will repent.', 'ὁ δὲ εἶπεν, Οὐχί, πάτερ Ἀβραάμ· ἀλλ'' ἐάν τις ἀπὸ νεκρῶν πορευθῇ πρὸς αὐτούς, μετανοήσουσιν.', 'ho de eipen, Ouchi, pater Abraam; all'' ean tis apo nekrōn poreuthē pros autous, metanoēsousin.', '"Nay, father Abraham" — the rich man disagrees with Abraham''s assessment of the Scripture''s sufficiency. He remains convinced that a resurrection appearance would be more effective than the written Word. "If one went unto them from the dead, they will repent" (metanoēsousin — they will change their minds completely). This is the voice of natural theology: extraordinary miracles should produce repentance. But Jesus''s entire ministry of miracles has already disproved this — miracles were witnessed and rejected (see 11:29-32; John 12:37).', NULL),
  (31, 'And he said unto him, If they hear not Moses and the prophets, neither will they be persuaded, though one rose from the dead.', 'εἶπεν δὲ αὐτῷ, Εἰ Μωϋσέως καὶ τῶν προφητῶν οὐκ ἀκούουσιν, οὐδὲ ἐάν τις ἐκ νεκρῶν ἀναστῇ πεισθήσονται.', 'eipen de autō, Ei Mōūseōs kai tōn prophētōn ouk akouousin, oude ean tis ek nekrōn anastē peisthēsontai.', '"If they hear not Moses and the prophets" (ouk akouousin — present tense: they are not hearing, they are currently not listening/obeying) — the issue is not lack of information but willful refusal of the revelation already given. "Neither will they be persuaded, though one rose from the dead" (oude...anastē peisthēsontai — not even if someone rises will they be persuaded). This verse prophesies the response to Jesus''s own resurrection: the Sanhedrin would bribe soldiers rather than believe (Matt 28:12-13). The heart that resists Scripture will rationalize away even resurrection.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 16;
